// And groups predicates with the AND operator between them.
func And(predicates ...predicate.SandboxTemplate) predicate.SandboxTemplate {
	return predicate.SandboxTemplate(sql.AndPredicates(predicates...))
}

// Or groups predicates with the OR operator between them.
func Or(predicates ...predicate.SandboxTemplate) predicate.SandboxTemplate {
	return predicate.SandboxTemplate(sql.OrPredicates(predicates...))
}

// Not applies the not operator on the given predicate.
func Not(p predicate.SandboxTemplate) predicate.SandboxTemplate {
	return predicate.SandboxTemplate(sql.NotPredicates(p))
}
